exports.getAbyssHoleUsageText = getAbyssHoleUsageText;

/** @type {Function} */
exports.getAbyssHoleUsageBodyText = getAbyssHoleUsageBodyText;

/** @type {Function} */
exports.createCommandGuideText = createCommandGuideText;
